B.J2=s(["(\u0627\u0644\u0628\u0642\u0631\u0629: 43) \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a\u0627\u0646 \u0628\u06d5\u062c\u06ce\u0628\u0647\u06ce\u0646\u0646 \u0648 \u0632\u06d5\u06a9\u0627\u062a \u0628\u062f\u06d5\u0646\u060c \u0648 \u0644\u06d5\u06af\u06d5\u06b5 \u06a9\u0695\u0646\u06c6\u0634\u0628\u06d5\u0631\u0627\u0646 \u06a9\u0695\u0646\u06c6\u0634 \u0628\u06d5\u0631\u0646.","(\u0627\u0644\u0639\u0646\u0643\u0628\u0648\u062a: 45) \u0628\u06ce\u06af\u0648\u0645\u0627\u0646 \u0646\u0648\u06ce\u0698 \u0645\u0631\u06c6\u06a4 \u0644\u06d5 \u06af\u0648\u0646\u0627\u0647 \u0648 \u062e\u0631\u0627\u067e\u06d5\u06a9\u0627\u0631\u0649 \u062f\u06d5\u067e\u0627\u0631\u06ce\u0632\u06ce\u062a.","(\u0637\u0647: 14) \u0646\u0648\u06ce\u0698 \u0628\u06a9\u06d5 \u0628\u06c6 \u06cc\u0627\u062f\u06a9\u0631\u062f\u0646\u06cc \u0645\u0646.","(\u0627\u0644\u0628\u0642\u0631\u0629: 153) \u062f\u0627\u0648\u0627\u06cc \u06cc\u0627\u0631\u0645\u06d5\u062a\u06cc \u0628\u06d5 \u0626\u0627\u0631\u0627\u0645\u06af\u0631\u062a\u0646 \u0648 \u0646\u0648\u06ce\u0698\u06a9\u0631\u062f\u0646 \u0628\u06a9\u06d5\u0646\u060c \u0628\u06ce\u06af\u0648\u0645\u0627\u0646 \u062e\u0648\u0627 \u0644\u06d5\u06af\u06d5\u06b5 \u0626\u0627\u0631\u0627\u0645\u06af\u0631\u0627\u0646\u06d5.","(\u0627\u0644\u0646\u0633\u0627\u0621: 103) \u0628\u06ce\u06af\u0648\u0645\u0627\u0646 \u0646\u0648\u06ce\u0698 \u0644\u06d5\u0633\u06d5\u0631 \u0628\u0627\u0648\u06d5\u0695\u062f\u0627\u0631\u0627\u0646 \u0641\u06d5\u0631\u0632\u06ce\u06a9\u06cc \u06a9\u0627\u062a \u062f\u06cc\u0627\u0631\u06cc\u06a9\u0631\u0627\u0648\u06d5.","(\u0627\u0644\u0645\u0624\u0645\u0646\u0648\u0646: 1-2) \u0628\u0627\u0648\u06d5\u0695\u062f\u0627\u0631\u0627\u0646 \u0633\u06d5\u0631\u0641\u0631\u0627\u0632 \u0628\u0648\u0648\u0646\u060c \u0626\u06d5\u0648\u0627\u0646\u06d5\u06cc \u0644\u06d5 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u06cc\u0627\u0646\u062f\u0627 \u0645\u0644\u06a9\u06d5\u0686 \u0648 \u0644\u06d5\u062e\u0648\u0627\u062a\u0631\u0633\u0646.","(\u0627\u0644\u0645\u0639\u0627\u0631\u062c: 22-23) \u062a\u06d5\u0646\u0647\u0627 \u0646\u0648\u06ce\u0698\u062e\u0648\u06ce\u0646\u0627\u0646 \u0646\u06d5\u0628\u06ce\u062a\u060c \u0626\u06d5\u0648\u0627\u0646\u06d5\u06cc \u0644\u06d5\u0633\u06d5\u0631 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u06cc\u0627\u0646 \u0628\u06d5\u0631\u062f\u06d5\u0648\u0627\u0645\u0646.","(\u0645\u0631\u064a\u0645: 59) \u067e\u0627\u0634\u0627\u0646 \u0646\u06d5\u0648\u06d5\u06cc\u06d5\u06a9 \u0647\u0627\u062a\u0646 \u06a9\u06d5 \u0646\u0648\u06ce\u0698\u06cc\u0627\u0646 \u0641\u06d5\u0648\u062a\u0627\u0646\u062f \u0648 \u0634\u0648\u06ce\u0646 \u0626\u0627\u0631\u06d5\u0632\u0648\u0648\u06d5\u06a9\u0627\u0646\u06cc\u0627\u0646 \u06a9\u06d5\u0648\u062a\u0646.","(\u0627\u0644\u0645\u062f\u062b\u0631: 42-43) \u062f\u06d5\u06b5\u06ce\u0646: \u0626\u06ce\u0645\u06d5 \u0644\u06d5 \u0646\u0648\u06ce\u0698\u062e\u0648\u06ce\u0646\u0627\u0646 \u0646\u06d5\u0628\u0648\u0648\u06cc\u0646.","(\u0627\u0644\u0628\u0642\u0631\u0629: 238) \u067e\u0627\u0631\u06ce\u0632\u06af\u0627\u0631\u06cc \u0644\u06d5 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a\u0627\u0646 \u0628\u06a9\u06d5\u0646\u060c \u0628\u06d5\u062a\u0627\u06cc\u0628\u06d5\u062a \u0646\u0648\u06ce\u0698\u06cc \u0646\u0627\u0648\u06d5\u0695\u0627\u0633\u062a (\u0639\u06d5\u0633\u0631).","(\u0627\u0644\u0623\u0639\u0644\u0649: 14-15) \u0633\u06d5\u0631\u0641\u0631\u0627\u0632 \u0628\u0648\u0648 \u0626\u06d5\u0648\u06d5\u06cc \u062e\u06c6\u06cc \u067e\u0627\u0643\u0643\u0631\u062f\u06d5\u0648\u06d5 \u0648 \u0646\u0648\u06ce\u0698\u06cc \u06a9\u0631\u062f.","(\u0625\u0628\u0631\u0627\u0647\u064a\u0645: 40) \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631\u0627\u060c \u0645\u0646 \u0648 \u0646\u06d5\u0648\u06d5\u06a9\u0627\u0646\u06cc\u0634\u0645 \u0628\u06a9\u06d5 \u0628\u06d5 \u0646\u0648\u06ce\u0698\u062e\u0648\u06ce\u0646.","(\u0644\u0642\u0645\u0627\u0646: 17) \u0626\u06d5\u06cc \u06a9\u0648\u0695\u06d5\u06a9\u06d5\u0645\u060c \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a \u0628\u06d5\u062c\u06ce\u0628\u0647\u06ce\u0646\u06d5 \u0648 \u0641\u06d5\u0631\u0645\u0627\u0646 \u0628\u06d5 \u0686\u0627\u06a9\u06d5 \u0628\u06a9\u06d5.","(\u0627\u0644\u0623\u0646\u0639\u0627\u0645: 162) \u0646\u0648\u06ce\u0698 \u0648 \u067e\u06d5\u0631\u0633\u062a\u0634 \u0648 \u0698\u06cc\u0627\u0646 \u0648 \u0645\u0631\u062f\u0646\u0645 \u0647\u06d5\u0631 \u0628\u06c6 \u062e\u0648\u0627\u06cc \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631\u06cc \u062c\u06cc\u0647\u0627\u0646\u06cc\u0627\u0646\u06d5.","(\u0627\u0644\u0631\u0639\u062f: 22) \u0626\u06d5\u0648\u0627\u0646\u06d5\u06cc \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u06cc\u0627\u0646 \u0628\u06d5\u062c\u06ce\u062f\u06d5\u0647\u06ce\u0646\u0646\u060c \u067e\u0627\u062f\u0627\u0634\u062a\u06cc \u06a9\u06c6\u062a\u0627\u06cc\u06cc (\u0628\u06d5\u0647\u06d5\u0634\u062a) \u0628\u06c6 \u0626\u06d5\u0648\u0627\u0646\u06d5\u06cc\u06d5.","(\u0627\u0644\u062d\u062c: 77) \u06a9\u0695\u0646\u06c6\u0634 \u0648 \u0633\u0648\u0698\u062f\u06d5 \u0628\u0628\u06d5\u0646 \u0648 \u0646\u0648\u06ce\u0698 \u0628\u06a9\u06d5\u0646 \u0628\u06c6 \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631\u062a\u0627\u0646.","(\u0627\u0644\u0646\u0648\u0631: 56) \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a\u0627\u0646 \u0628\u06d5\u062c\u06ce\u0628\u0647\u06ce\u0646\u0646\u060c \u0628\u06c6 \u0626\u06d5\u0648\u06d5\u06cc \u0695\u06d5\u062d\u0645\u062a\u0627\u0646 \u067e\u06ce\u0628\u06a9\u0631\u06ce\u062a.","(\u0627\u0644\u0643\u0648\u062b\u0631: 2) \u0646\u0648\u06ce\u0698 \u0628\u06c6 \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631\u062a \u0628\u06a9\u06d5 \u0648 \u0642\u0648\u0631\u0628\u0627\u0646\u06cc \u0628\u06a9\u06d5.","(\u0627\u0644\u0628\u064a\u0646\u0629: 5) \u0646\u0648\u06ce\u0698 \u0628\u06a9\u06d5\u0646 \u0648 \u0632\u06d5\u06a9\u0627\u062a \u0628\u062f\u06d5\u0646\u060c \u0626\u06d5\u0645\u06d5\u0634 \u0626\u0627\u06cc\u06cc\u0646\u06cc \u0695\u0627\u0633\u062a\u06d5\u0642\u06cc\u0646\u06d5\u06cc\u06d5.","(\u0627\u0644\u0645\u0627\u0626\u062f\u0629: 55) \u0628\u0627\u0648\u06d5\u0695\u062f\u0627\u0631\u0627\u0646\u06cc \u0695\u0627\u0633\u062a\u06d5\u0642\u06cc\u0646\u06d5 \u0626\u06d5\u0648\u0627\u0646\u06d5\u06cc\u06d5\u0646 \u06a9\u06d5 \u0646\u0648\u06ce\u0698 \u062f\u06d5\u06a9\u06d5\u0646 \u0648 \u0632\u06d5\u06a9\u0627\u062a \u062f\u06d5\u062f\u06d5\u0646.","(\u0627\u0644\u062a\u0648\u0628\u0629: 71) \u0628\u0627\u0648\u06d5\u0695\u062f\u0627\u0631\u0627\u0646\u06cc \u0695\u0627\u0633\u062a\u06d5\u0642\u06cc\u0646\u06d5 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u06cc\u0627\u0646 \u0628\u06d5\u062c\u06ce\u062f\u06d5\u0647\u06ce\u0646\u0646.","(\u0627\u0644\u0645\u0632\u0645\u0644: 20) \u0646\u0648\u06ce\u0698 \u0628\u06d5\u062c\u06ce\u0628\u0647\u06ce\u0646\u0646 \u0648 \u0632\u06d5\u06a9\u0627\u062a \u0628\u062f\u06d5\u0646 \u0648 \u0642\u06d5\u0631\u0632\u06cc \u062d\u06d5\u0633\u06d5\u0646\u06d5 \u0628\u062f\u06d5\u0646 \u0628\u06d5 \u062e\u0648\u0627.","(\u0627\u0644\u0628\u0642\u0631\u0629: 3) \u0628\u0627\u0648\u06d5\u0695\u062f\u0627\u0631\u0627\u0646 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u06cc\u0627\u0646 \u0628\u06d5\u062c\u06ce\u062f\u06d5\u0647\u06ce\u0646\u0646 \u0648 \u0644\u06d5\u0648\u06d5\u06cc \u067e\u06ce\u0645\u0627\u0646 \u062f\u0627\u0648\u0646 \u062f\u06d5\u0628\u06d5\u062e\u0634\u0646.","(\u0627\u0644\u0645\u0627\u0626\u062f\u0629: 12) \u062e\u0648\u0627 \u0641\u06d5\u0631\u0645\u0648\u0648\u06cc: \u0628\u06d5\u0695\u0627\u0633\u062a\u06cc \u0645\u0646 \u0644\u06d5\u06af\u06d5\u06b5\u062a\u0627\u0646\u0645 \u0626\u06d5\u06af\u06d5\u0631 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a\u0627\u0646 \u0628\u06d5\u062c\u06ce\u0628\u0647\u06ce\u0646\u0646.","(\u0627\u0644\u0628\u0642\u0631\u0629: 238) \u0628\u06d5 \u0645\u0644\u06a9\u06d5\u0686\u06cc\u06cc\u06d5\u0648\u06d5 \u0628\u06c6 \u062e\u0648\u0627 \u0695\u0627\u0648\u06d5\u0633\u062a\u0646 \u2014 \u0646\u0648\u06ce\u0698 \u06a9\u0631\u062f\u06d5 \u0628\u0627\u0648\u06d5\u0695\u06cc \u0646\u06cc\u0634\u062a\u06d5\u062c\u06ce\u0628\u0648\u0648.","\u06cc\u06d5\u06a9\u06d5\u0645 \u0634\u062a \u06a9\u06d5 \u0645\u0631\u06c6\u06a4 \u0644\u06d5 \u0695\u06c6\u0698\u06cc \u062f\u0648\u0627\u06cc\u06cc\u062f\u0627 \u0644\u06ce\u067e\u0631\u0633\u06cc\u0646\u06d5\u0648\u06d5\u06cc \u0644\u06d5\u0633\u06d5\u0631 \u062f\u06d5\u06a9\u0631\u06ce\u062a\u060c \u0646\u0648\u06ce\u0698\u06d5.","\u062c\u06cc\u0627\u0648\u0627\u0632\u06cc \u0646\u06ce\u0648\u0627\u0646 \u0645\u0631\u06c6\u06a4 \u0648 \u0628\u06ce\u0628\u0627\u0648\u06d5\u0695\u06cc\u060c \u0648\u0627\u0632\u0647\u06ce\u0646\u0627\u0646\u06d5 \u0644\u06d5 \u0646\u0648\u06ce\u0698.","\u0646\u0648\u06ce\u0698 \u06a9\u06c6\u06b5\u06d5\u06a9\u06d5\u06cc \u0626\u0627\u06cc\u06cc\u0646\u06d5\u060c \u0647\u06d5\u0631\u06a9\u06d5\u0633\u06ce\u06a9 \u062f\u0627\u06cc\u0645\u06d5\u0632\u0631\u06ce\u0646\u06ce\u062a \u0626\u0627\u06cc\u06cc\u0646\u06d5\u06a9\u06d5\u06cc \u067e\u0627\u0631\u0627\u0633\u062a\u0648\u0648\u06d5.","\u0647\u06d5\u0631\u06a9\u06d5\u0633\u06ce\u06a9 \u0646\u0648\u06ce\u0698\u06ce\u06a9\u06cc \u0644\u06d5\u0628\u06cc\u0631\u0686\u0648\u0648\u060c \u06a9\u0627\u062a\u06ce\u06a9 \u0628\u06cc\u0631\u06cc \u0647\u0627\u062a\u06d5\u0648\u06d5 \u06cc\u06d5\u06a9\u0633\u06d5\u0631 \u0628\u06cc\u06a9\u0627\u062a\u06d5\u0648\u06d5.","\u0646\u0645\u0648\u0648\u0646\u06d5\u06cc \u067e\u06ce\u0646\u062c \u0641\u06d5\u0631\u0632\u06cc \u0646\u0648\u06ce\u0698 \u0648\u06d5\u06a9\u0648 \u0634\u0648\u0634\u062a\u0646\u06d5 \u0628\u06d5 \u0626\u0627\u0648\u06cc \u0695\u0648\u0648\u0628\u0627\u0631\u06cc \u062e\u0648\u06b5\u0642 \u0647\u06d5\u0645\u0648\u0648 \u0695\u06c6\u0698 \u2014 \u0647\u06cc\u0686 \u0686\u06b5\u06a9\u06ce\u06a9 \u0646\u0627\u0645\u0627\u0648\u06ce\u062a.","\u0646\u0648\u06ce\u0698\u06cc \u0628\u06d5\u06a9\u06c6\u0645\u06d5\u06b5 (\u062c\u06d5\u0645\u0627\u0639\u06d5\u062a) \u0628\u06cc\u0633\u062a \u0648 \u062d\u06d5\u0648\u062a \u067e\u0644\u06d5 \u0644\u06d5 \u0646\u0648\u06ce\u0698\u06cc \u062a\u06d5\u0646\u0647\u0627 \u062e\u06ce\u0631\u062a\u0631\u06d5.","\u062e\u0631\u0627\u067e\u062a\u0631\u06cc\u0646 \u062f\u0632 \u0626\u06d5\u0648\u06d5\u06cc\u06d5 \u06a9\u06d5 \u0644\u06d5 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u06d5\u06cc \u062f\u06d5\u062f\u0632\u06ce\u062a \u2014 \u0695\u06a9\u0648\u0639 \u0648 \u0633\u0648\u0698\u062f\u06d5\u06cc \u062a\u06d5\u0648\u0627\u0648 \u0646\u0627\u06a9\u0627\u062a.","\u0642\u0648\u0631\u0633\u062a\u0631\u06cc\u0646 \u0646\u0648\u06ce\u0698 \u0644\u06d5\u0633\u06d5\u0631 \u062f\u0648\u0648\u0695\u0648\u0648\u06d5\u06a9\u0627\u0646 \u0646\u0648\u06ce\u0698\u06cc \u0639\u06cc\u0634\u0627 \u0648 \u0628\u06d5\u06cc\u0627\u0646\u06cc\u06cc\u06d5.","\u0647\u06d5\u0631\u06a9\u06d5\u0633\u06ce\u06a9 \u067e\u0627\u0631\u06ce\u0632\u06af\u0627\u0631\u06cc \u0644\u06d5 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u06cc \u0628\u06a9\u0627\u062a\u060c \u0644\u06d5 \u0695\u06c6\u0698\u06cc \u062f\u0648\u0627\u06cc\u06cc\u062f\u0627 \u0695\u0648\u0648\u0646\u0627\u06a9\u06cc \u0648 \u0695\u0632\u06af\u0627\u0631\u0628\u0648\u0648\u0646\u06cc \u0647\u06d5\u06cc\u06d5.","\u06a9\u0644\u06cc\u0644\u06cc \u0628\u06d5\u0647\u06d5\u0634\u062a \u0646\u0648\u06ce\u0698\u06d5.","\u067e\u06ce\u063a\u06d5\u0645\u0628\u06d5\u0631 (\u062f.\u062e) \u06a9\u0627\u062a\u06ce\u06a9 \u062a\u0648\u0648\u0634\u06cc \u06a9\u06ce\u0634\u06d5\u06cc\u06d5\u06a9\u06cc \u06af\u06d5\u0648\u0631\u06d5 \u062f\u06d5\u0628\u0648\u0648\u060c \u067e\u06d5\u0646\u0627\u06cc \u0628\u06c6 \u0646\u0648\u06ce\u0698 \u062f\u06d5\u0628\u0631\u062f.","\u0646\u0648\u06ce\u0698 \u0695\u0648\u0648\u0646\u0627\u06a9\u06cc\u06cc\u06d5 \u0628\u06c6 \u062f\u06b5 \u0648 \u062f\u06d5\u0631\u0648\u0648\u0646.","\u0647\u06d5\u0631\u06a9\u06d5\u0633\u06ce\u06a9 \u0628\u06d5 \u0626\u06d5\u0646\u0642\u06d5\u0633\u062a \u0646\u0648\u06ce\u0698\u06cc \u0639\u06d5\u0633\u0631 \u062c\u06ce\u0628\u0647\u06ce\u06b5\u06ce\u062a\u060c \u06a9\u0631\u062f\u06d5\u0648\u06d5\u06a9\u0627\u0646\u06cc \u0628\u06d5\u062a\u0627\u06b5 \u062f\u06d5\u0628\u0646\u06d5\u0648\u06d5.","\u06a9\u0627\u062a\u06ce\u06a9 \u0628\u06d5\u0646\u062f\u06d5 \u0633\u0648\u0698\u062f\u06d5 \u062f\u06d5\u0628\u0627\u062a\u060c \u0644\u06d5 \u0647\u06d5\u0645\u0648\u0648 \u06a9\u0627\u062a\u06ce\u06a9 \u0632\u06cc\u0627\u062a\u0631 \u0644\u06d5 \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631\u06cc \u0646\u0632\u06cc\u06a9\u06d5.","\u0633\u0627\u0631\u062f\u06a9\u0631\u062f\u0646\u06d5\u0648\u06d5\u06cc \u0686\u0627\u0648\u06cc \u0645\u0646 \u2014 \u0626\u0627\u0631\u0627\u0645\u06cc \u062f\u06b5\u0645 \u2014 \u0644\u06d5 \u0646\u0648\u06ce\u0698\u062f\u0627 \u062f\u0627\u0646\u0631\u0627\u0648\u06d5.","\u0641\u06d5\u0631\u0645\u0627\u0646 \u0628\u06d5 \u0645\u0646\u062f\u0627\u06b5\u06d5\u06a9\u0627\u0646\u062a\u0627\u0646 \u0628\u06a9\u06d5\u0646 \u0644\u06d5 \u062d\u06d5\u0648\u062a \u0633\u0627\u06b5\u06cc\u062f\u0627 \u0646\u0648\u06ce\u0698 \u0628\u06a9\u06d5\u0646.","\u0628\u0627\u0634\u062a\u0631\u06cc\u0646 \u06a9\u0631\u062f\u06d5\u0648\u06d5 \u0646\u0648\u06ce\u0698\u06a9\u0631\u062f\u0646\u06d5 \u0644\u06d5 \u0633\u06d5\u0631\u06d5\u062a\u0627\u06cc \u06a9\u0627\u062a\u06cc \u062e\u06c6\u06cc\u062f\u0627.","\u0641\u0631\u06cc\u0634\u062a\u06d5\u06a9\u0627\u0646 \u062f\u0627\u0648\u0627\u06cc \u0644\u06ce\u062e\u06c6\u0634\u0628\u0648\u0648\u0646 \u062f\u06d5\u06a9\u06d5\u0646 \u0628\u06c6 \u06a9\u06d5\u0633\u06ce\u06a9 \u06a9\u06d5 \u0644\u06d5 \u0634\u0648\u06ce\u0646\u06cc \u0646\u0648\u06ce\u0698\u06d5\u06a9\u06d5\u06cc \u062f\u06d5\u0645\u06ce\u0646\u06ce\u062a\u06d5\u0648\u06d5 \u0628\u06d5 \u062f\u06d5\u0633\u062a\u0646\u0648\u06ce\u0698.","\u0647\u06d5\u0631\u06a9\u06d5\u0633\u06ce\u06a9 \u062f\u0648\u0648 \u0641\u06ce\u0646\u0643\u0643\u06d5\u0631\u06d5\u0648\u06d5\u06a9\u06d5 \u2014 \u0646\u0648\u06ce\u0698\u06cc \u0628\u06d5\u06cc\u0627\u0646\u06cc \u0648 \u0639\u06d5\u0633\u0631 \u2014 \u0628\u06a9\u0627\u062a\u060c \u062f\u06d5\u0686\u06ce\u062a\u06d5 \u0628\u06d5\u0647\u06d5\u0634\u062a\u06d5\u0648\u06d5.","\u067e\u06ce\u063a\u06d5\u0645\u0628\u06d5\u0631 (\u062f.\u062e) \u062f\u06d5\u06cc\u0641\u06d5\u0631\u0645\u0648\u0648: \u0626\u06d5\u06cc \u0628\u06cc\u0644\u0627\u0644\u060c \u0647\u06d5\u0633\u062a\u06d5 \u0648 \u0628\u06d5 \u0646\u0648\u06ce\u0698 \u0626\u0627\u0631\u0627\u0645\u06cc\u0645\u0627\u0646 \u067e\u06ce\u0628\u0628\u06d5\u062e\u0634\u06d5.","\u0626\u06d5\u06af\u06d5\u0631 \u062e\u06d5\u06b5\u06a9 \u062f\u06d5\u06cc\u0627\u0646\u0632\u0627\u0646\u06cc \u0686 \u067e\u0627\u062f\u0627\u0634\u062a\u06ce\u06a9 \u0644\u06d5 \u0628\u0627\u0646\u06af\u062f\u0627\u0646 \u0647\u06d5\u06cc\u06d5\u060c \u06a9\u06ce\u0628\u0695\u06a9\u06ce\u06cc\u0627\u0646 \u0644\u06d5\u0633\u06d5\u0631 \u062f\u06d5\u06a9\u0631\u062f.","\u0647\u06cc\u0686 \u0628\u06d5\u0646\u062f\u06d5\u06cc\u06d5\u06a9 \u0646\u06cc\u06cc\u06d5 \u0633\u0648\u0698\u062f\u06d5\u06cc\u06d5\u06a9 \u0628\u06c6 \u062e\u0648\u0627 \u0628\u0628\u0627\u062a\u060c \u0645\u06d5\u06af\u06d5\u0631 \u062e\u0648\u0627 \u067e\u0644\u06d5\u06cc\u06d5\u06a9\u06cc \u0628\u06d5\u0631\u0632 \u0628\u06a9\u0627\u062a\u06d5\u0648\u06d5 \u0648 \u06af\u0648\u0646\u0627\u0647\u06ce\u06a9\u06cc \u0644\u06ce \u0628\u0633\u0695\u06ce\u062a\u06d5\u0648\u06d5.","\u0646\u0648\u06ce\u0698\u06d5 \u067e\u06ce\u0646\u062c \u0641\u06d5\u0631\u0632\u06d5\u06a9\u0627\u0646 \u062a\u0627 \u0646\u0648\u06ce\u0698\u06cc \u0647\u06d5\u06cc\u0646\u06cc \u062f\u0627\u0647\u0627\u062a\u0648\u0648\u060c \u06af\u0648\u0646\u0627\u0647\u06d5\u06a9\u0627\u0646\u06cc \u0646\u06ce\u0648\u0627\u0646\u06cc\u0627\u0646 \u062f\u06d5\u0633\u0695\u0646\u06d5\u0648\u06d5.","\u0686\u0627\u0648\u06d5\u0695\u06ce\u06a9\u0631\u062f\u0646\u06cc \u0646\u0648\u06ce\u0698 \u0628\u06c6 \u0646\u0648\u06ce\u0698\u06ce\u06a9\u06cc \u062a\u0631 \u0648\u06d5\u06a9 \u067e\u0627\u0631\u06ce\u0632\u06af\u0627\u0631\u06cc\u06cc\u06d5 \u0644\u06d5 \u0695\u06ce\u06af\u0627\u06cc \u062e\u0648\u0627\u062f\u0627.","\u06a9\u06d5\u0633\u06ce\u06a9 \u06a9\u06d5 \u0646\u0648\u06ce\u0698\u06cc \u0628\u06d5\u06cc\u0627\u0646\u06cc \u062f\u06d5\u06a9\u0627\u062a\u060c \u0644\u06d5 \u067e\u0627\u0631\u06ce\u0632\u06af\u0627\u0631\u06cc \u0648 \u067e\u06d5\u0646\u0627\u06cc \u062e\u0648\u0627\u062f\u0627\u06cc\u06d5 \u0626\u06d5\u0648 \u0695\u06c6\u0698\u06d5.","\u0647\u06d5\u0631\u06af\u06cc\u0632 \u0645\u06d5\u06b5\u06ce \u06a9\u0627\u062a\u0645 \u0646\u06cc\u06cc\u06d5 \u0628\u06c6 \u0646\u0648\u06ce\u0698\u060c \u06a9\u0627\u062a\u06d5\u06a9\u0627\u0646 \u0645\u0648\u06b5\u06a9\u06cc \u0646\u0648\u06ce\u0698\u062e\u0648\u06ce\u0646\u0627\u0646\u0646.","\u0626\u06d5\u06af\u06d5\u0631 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a \u0695\u06ce\u06a9\u062e\u0633\u062a\u060c \u062f\u06b5\u0646\u06cc\u0627\u0628\u06d5 \u0647\u06d5\u0645\u0648\u0648 \u06a9\u0627\u0631\u06d5\u06a9\u0627\u0646\u06cc \u0698\u06cc\u0627\u0646\u062a \u0695\u06ce\u06a9\u062f\u06d5\u0628\u0646\u06d5\u0648\u06d5.","\u0646\u0648\u06ce\u0698\u06cc \u0641\u06d5\u0648\u062a\u0627\u0648 \u0648\u06d5\u06a9 \u0642\u06d5\u0631\u0632\u06ce\u06a9\u06cc \u06af\u06d5\u0648\u0631\u06d5\u06cc\u06d5\u060c \u0632\u0648\u0648 \u0628\u06cc\u06af\u06d5\u0695\u06ce\u0646\u06d5\u0648\u06d5 \u067e\u06ce\u0634 \u0626\u06d5\u0648\u06d5\u06cc \u0645\u06d5\u0631\u06af \u06cc\u06d5\u062e\u06d5\u062a \u0628\u06af\u0631\u06ce\u062a.","\u0634\u06d5\u0631\u0645\u06d5 \u0628\u06c6 \u0628\u0627\u0648\u06d5\u0695\u062f\u0627\u0631\u06ce\u06a9 \u06a9\u06d5 \u06af\u0648\u06ce\u06cc \u0644\u06d5 \u0628\u0627\u0646\u06af \u0628\u06ce\u062a \u0648 \u0648\u06d5\u06b5\u0627\u0645\u06cc \u0628\u0627\u0646\u06af\u06d5\u0648\u0627\u0632\u06cc \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631\u06cc \u0646\u06d5\u062f\u0627\u062a\u06d5\u0648\u06d5.","\u0646\u0648\u06ce\u0698 \u062d\u06d5\u0628\u0644\u06ce\u06a9\u06cc \u067e\u06d5\u06cc\u0648\u06d5\u0646\u062f\u06cc\u06cc\u06d5 \u0644\u06d5 \u0646\u06ce\u0648\u0627\u0646 \u062a\u06c6 \u0648 \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631\u062a \u2014 \u0645\u06d5\u0647\u06ce\u06b5\u06d5 \u0628\u067e\u0686\u0695\u06ce\u062a.","\u06a9\u0627\u062a\u06ce\u06a9 \u062e\u06d5\u0645\u06d5\u06a9\u0627\u0646\u062a \u0632\u06c6\u0631 \u062f\u06d5\u0628\u0646\u060c \u0628\u0627 \u0633\u0648\u0698\u062f\u06d5\u06a9\u0627\u0646\u062a \u062f\u0631\u06ce\u0698\u062a\u0631 \u0628\u0646.","\u0648\u0627\u0632\u0647\u06ce\u0646\u0627\u0646 \u0644\u06d5 \u0646\u0648\u06ce\u0698\u060c \u0633\u06d5\u0631\u06d5\u062a\u0627\u06cc \u0647\u06d5\u0645\u0648\u0648 \u0634\u06a9\u0633\u062a \u0648 \u062f\u06b5\u06d5\u0695\u0627\u0648\u06a9\u06ce\u06cc\u06d5\u06a9\u06d5 \u0644\u06d5 \u0698\u06cc\u0627\u0646\u062f\u0627.","\u0626\u06d5\u0648\u06d5\u06cc \u0644\u06d5 \u06a9\u0627\u062a\u06cc \u062e\u06c6\u0634\u06cc\u062f\u0627 \u062e\u0648\u0627 \u0628\u0646\u0627\u0633\u06ce\u062a\u060c \u062e\u0648\u0627 \u0644\u06d5 \u06a9\u0627\u062a\u06cc \u062a\u06d5\u0646\u06af\u0627\u0646\u06d5\u062f\u0627 \u0641\u0631\u06cc\u0627\u06cc \u062f\u06d5\u06a9\u06d5\u0648\u06ce\u062a.","\u0626\u06d5\u06af\u06d5\u0631 \u0646\u0648\u06ce\u0698\u06ce\u06a9\u062a \u0641\u06d5\u0648\u062a\u0627\u060c \u0628\u0627 \u062f\u06b5\u062a \u062e\u06d5\u0645\u0628\u0627\u0631 \u0628\u06ce\u062a \u2014 \u062f\u06cc\u062f\u0627\u0631\u06ce\u06a9\u06cc \u06af\u06d5\u0648\u0631\u06d5\u062a \u0644\u06d5\u06af\u06d5\u06b5 \u067e\u0627\u0634\u0627\u06cc \u067e\u0627\u0634\u0627\u06a9\u0627\u0646 \u0644\u06d5\u062f\u06d5\u0633\u062a\u062f\u0627\u0648\u06d5.","\u0646\u0648\u06ce\u0698 \u062a\u06d5\u0646\u0647\u0627 \u062c\u0648\u06b5\u06d5\u06cc \u062c\u06d5\u0633\u062a\u06d5 \u0646\u06cc\u06cc\u06d5\u060c \u0628\u06d5\u06b5\u0643\u0648 \u0626\u0627\u0631\u0627\u0645\u06cc\u06cc\u06d5 \u0628\u06c6 \u0695\u06c6\u062d \u0648 \u062f\u06b5.","\u067e\u06d5\u0644\u06d5\u06a9\u0631\u062f\u0646 \u0644\u06d5 \u0642\u06d5\u0632\u0627\u06a9\u0631\u062f\u0646\u06cc \u0646\u0648\u06ce\u0698\u06cc \u0641\u06d5\u0648\u062a\u0627\u0648 \u0646\u06cc\u0634\u0627\u0646\u06d5\u06cc \u0632\u06cc\u0646\u062f\u0648\u0648\u06cc\u06cc \u062f\u06b5\u06cc \u0628\u0627\u0648\u06d5\u0695\u062f\u0627\u0631\u06d5.","\u067e\u06ce\u0634 \u0626\u06d5\u0648\u06d5\u06cc \u0646\u0648\u06ce\u0698\u06cc \u06a9\u06c6\u062a\u0627\u06cc\u06cc\u062a \u0644\u06d5\u0633\u06d5\u0631 \u0628\u06a9\u0631\u06ce\u062a \u06a9\u06d5 \u06a9\u0695\u0646\u06c6\u0634\u06cc \u062a\u06ce\u062f\u0627 \u0646\u06cc\u06cc\u06d5\u060c \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a \u0628\u06d5\u06a9\u0695\u0646\u06c6\u0634\u06d5\u0648\u06d5 \u0628\u06a9\u06d5.","\u0647\u06cc\u0686 \u0633\u06d5\u0631\u06a9\u06d5\u0648\u062a\u0646\u06ce\u06a9 \u0628\u06d5\u0628\u06ce \u0633\u0648\u0698\u062f\u06d5\u0628\u0631\u062f\u0646 \u0628\u06c6 \u062e\u0648\u062f\u0627\u060c \u062a\u0627\u0645 \u0648 \u0686\u06ce\u0698 \u0648 \u0628\u06d5\u0631\u06d5\u06a9\u06d5\u062a\u06cc \u0646\u06cc\u06cc\u06d5.","\u0626\u06d5\u06af\u06d5\u0631 \u062f\u06d5\u062a\u06d5\u0648\u06ce\u062a \u062e\u0648\u0627 \u0644\u06d5\u06af\u06d5\u06b5\u062a \u0642\u0633\u06d5 \u0628\u06a9\u0627\u062a\u060c \u0628\u06c6 \u0646\u0648\u06ce\u0698 \u0647\u06d5\u0633\u062a\u06d5.","\u0628\u06d5\u062c\u06ce\u0647\u06ce\u0634\u062a\u0646\u06cc \u0646\u0648\u06ce\u0698 \u062f\u06b5 \u0695\u06d5\u0642 \u062f\u06d5\u06a9\u0627\u062a \u0648 \u0628\u06d5\u0631\u06d5\u06a9\u06d5\u062a \u0644\u06d5 \u062a\u06d5\u0645\u06d5\u0646 \u062f\u06d5\u0628\u0627\u062a.","\u0647\u06d5\u0645\u0648\u0648 \u0695\u06c6\u0698\u06ce\u06a9 \u062f\u06d5\u0631\u0641\u06d5\u062a\u06ce\u06a9\u06cc \u0646\u0648\u06ce\u06cc\u06d5 \u0628\u06c6 \u06af\u06d5\u0695\u0627\u0646\u06d5\u0648\u06d5 \u0628\u06c6 \u0644\u0627\u06cc \u062e\u0648\u0627 \u2014 \u0626\u06d5\u0645\u0695\u06c6\u062a \u0628\u06d5\u0646\u0648\u06ce\u0698\u06a9\u0631\u062f\u0646 \u062c\u06cc\u0627\u0648\u0627\u0632 \u0628\u06a9\u06d5.","\u0626\u06d5\u06af\u06d5\u0631 \u0646\u06d5\u062e\u06c6\u0634\u06cc\u062a\u060c \u0628\u06d5 \u062f\u0627\u0646\u06cc\u0634\u062a\u0646 \u06cc\u0627\u0646 \u067e\u0627\u06b5\u06a9\u06d5\u0648\u062a\u0646\u06d5\u0648\u06d5 \u0646\u0648\u06ce\u0698 \u0628\u06a9\u06d5\u060c \u0628\u06d5\u06b5\u0627\u0645 \u0647\u06d5\u0631\u06af\u06cc\u0632 \u062c\u06ce\u06cc \u0645\u06d5\u0647\u06ce\u06b5\u06d5.","\u0646\u0648\u06ce\u0698\u06cc \u0634\u06d5\u0648\u06d5\u06a9\u0627\u0646\u062a (\u062a\u06d5\u0647\u06d5\u062c\u0648\u062f) \u0628\u06a9\u06d5 \u0628\u06d5 \u0695\u0648\u0648\u0646\u0627\u06a9\u06cc \u0628\u06c6 \u062a\u0627\u0631\u06cc\u06a9\u06cc \u06af\u06c6\u0695\u06d5\u06a9\u06d5\u062a.","\u0647\u06d5\u0631\u06a9\u06d5\u0633\u06ce\u06a9 \u0642\u06d5\u062f\u0631\u06cc \u0646\u0648\u06ce\u0698 \u0646\u06d5\u0632\u0627\u0646\u06ce\u062a\u060c \u0642\u06d5\u062f\u0631\u06cc \u0647\u06cc\u0686 \u0646\u06cc\u0639\u0645\u06d5\u062a\u06ce\u06a9\u06cc \u062a\u0631\u06cc \u062e\u0648\u062f\u0627 \u0646\u0627\u0632\u0627\u0646\u06ce\u062a.","\u0644\u06d5\u0628\u0631\u06cc \u06af\u0644\u06d5\u06cc\u06cc \u0644\u06d5 \u06a9\u06ce\u0634\u06d5\u06a9\u0627\u0646\u062a\u060c \u0633\u06d5\u0631\u06d5\u062a\u0627 \u06af\u0644\u06d5\u06cc\u06cc \u0644\u06d5 \u06a9\u06d5\u0645\u062a\u06d5\u0631\u062e\u06d5\u0645\u06cc \u0646\u0648\u06ce\u0698\u06d5\u06a9\u0627\u0646\u062a \u0628\u06a9\u06d5.","\u06a9\u0627\u062a\u06ce\u06a9 \u0648\u0627\u062f\u06d5\u06cc \u0646\u0648\u06ce\u0698 \u062f\u06ce\u062a\u060c \u0628\u0627\u06cc\u062f \u0647\u06d5\u0645\u0648\u0648 \u06a9\u0627\u0631\u06d5\u06a9\u0627\u0646\u06cc \u062a\u0631 \u0628\u0648\u06d5\u0633\u062a\u0646 \u2014 \u0626\u0627\u06a9\u0627\u0645\u06cc \u062e\u0648\u062f\u0627\u06cc\u06d5.","\u062f\u0631\u06d5\u0646\u06af \u06a9\u06d5\u0648\u062a\u0646 \u0644\u06d5 \u0646\u0648\u06ce\u0698\u060c \u062f\u06d5\u0631\u06af\u0627\u06cc \u062f\u0631\u06d5\u0646\u06af \u06a9\u06d5\u0648\u062a\u0646 \u0644\u06d5 \u0647\u06d5\u0645\u0648\u0648 \u062e\u06ce\u0631 \u0648 \u0628\u06d5\u0631\u06d5\u06a9\u06d5\u062a\u06d5.","\u0646\u0648\u06ce\u0698 \u0628\u0627\u0634\u062a\u0631\u06cc\u0646 \u0648\u06d5\u0628\u06d5\u0631\u0647\u06ce\u0646\u0627\u0646\u06d5 \u0628\u06c6 \u062f\u0648\u0627\u0695\u06c6\u0698\u060c \u06a9\u06d5 \u0647\u06d5\u0631\u06af\u06cc\u0632 \u0632\u06cc\u0627\u0646\u06cc \u062a\u06ce\u062f\u0627 \u0646\u06cc\u06cc\u06d5.","\u0626\u06d5\u0648 \u0626\u0627\u0631\u0627\u0645\u06cc\u06cc\u06d5\u06cc \u06a9\u06d5 \u0644\u06d5 \u06a9\u0644\u06cc\u0646\u06cc\u06a9\u06d5\u06a9\u0627\u0646 \u0628\u06d5\u062f\u0648\u0627\u06cc\u062f\u0627 \u062f\u06d5\u06af\u06d5\u0695\u06ce\u06cc\u062a\u060c \u0632\u06c6\u0631\u062c\u0627\u0631 \u062a\u06d5\u0646\u0647\u0627 \u0644\u06d5\u0633\u06d5\u0631 \u0628\u06d5\u0631\u0645\u0627\u06b5\u06d5\u06a9\u06d5\u062a \u062f\u06d5\u062f\u06c6\u0632\u0631\u06ce\u062a\u06d5\u0648\u06d5.","\u062a\u0627 \u06a9\u0627\u062a \u0645\u0627\u0648\u06d5 \u0648 \u0647\u06d5\u0646\u0627\u0633\u06d5 \u062f\u06d5\u062f\u06d5\u06cc\u062a\u060c \u062f\u06d5\u062a\u0648\u0627\u0646\u06cc\u062a \u062a\u06c6\u0628\u06d5 \u0628\u06a9\u06d5\u06cc\u062a \u0648 \u0642\u06d5\u0631\u06d5\u0628\u0648\u0648\u06cc \u0646\u0648\u06ce\u0698\u06cc \u0641\u06d5\u0648\u062a\u0627\u0648\u06d5\u06a9\u0627\u0646\u062a \u0628\u06a9\u06d5\u06cc\u062a\u06d5\u0648\u06d5.","\u0647\u06d5\u0633\u062a\u06d5! \u062e\u0648\u062f\u0627 \u0628\u06d5\u0648 \u06af\u06d5\u0648\u0631\u06d5\u06cc\u06cc\u06d5\u06cc \u062e\u06c6\u06cc \u0686\u0627\u0648\u06d5\u0695\u06ce\u06cc \u062f\u06d5\u0646\u06af\u06cc \u062a\u06c6\u06cc\u06d5 \u0644\u06d5\u0646\u0627\u0648 \u0633\u0648\u0698\u062f\u06d5\u062f\u0627.","\u0647\u06cc\u0686 \u06af\u0648\u0646\u0627\u0647\u06ce\u06a9 \u0647\u06ce\u0646\u062f\u06d5 \u06af\u06d5\u0648\u0631\u06d5 \u0646\u06cc\u06cc\u06d5 \u06a9\u06d5 \u0695\u06ce\u06af\u06d5\u062a \u0644\u06ce\u0628\u06af\u0631\u06ce\u062a \u0628\u06af\u06d5\u0695\u06ce\u06cc\u062a\u06d5\u0648\u06d5 \u0648 \u062f\u0627\u0648\u0627\u06cc \u0644\u06ce\u062e\u06c6\u0634\u0628\u0648\u0648\u0646 \u0628\u06a9\u06d5\u06cc\u062a.","\u0626\u06d5\u0645\u0695\u06c6 \u062f\u06d5\u0633\u062a \u067e\u06ce\u0628\u06a9\u06d5! \u062a\u06d5\u0646\u0627\u0646\u06d5\u062a \u0626\u06d5\u06af\u06d5\u0631 \u062a\u06d5\u0646\u0647\u0627 \u06cc\u06d5\u06a9 \u0646\u0648\u06ce\u0698\u06cc\u0634 \u0628\u06a9\u06d5\u06cc\u062a\u060c \u0647\u06d5\u0632\u0627\u0631 \u062c\u0627\u0631 \u0628\u0627\u0634\u062a\u0631\u06d5 \u0644\u06d5 \u0648\u0627\u0632\u0647\u06ce\u0646\u0627\u0646\u06cc \u062a\u06d5\u0648\u0627\u0648.","\u0647\u06d5\u0645\u0648\u0648 \u0633\u0648\u0698\u062f\u06d5\u06cc\u06d5\u06a9\u060c \u0647\u06d5\u0646\u06af\u0627\u0648\u06ce\u06a9\u06d5 \u0628\u06d5\u0631\u06d5\u0648 \u0628\u06d5\u0647\u06d5\u0634\u062a \u0648 \u062f\u0648\u0648\u0631\u062e\u0633\u062a\u0646\u06d5\u0648\u06d5 \u0644\u06d5 \u062f\u06c6\u0632\u06d5\u062e.","\u0628\u0627\u0648\u06d5\u0695\u062a \u0628\u06d5 \u0695\u06d5\u062d\u0645\u06cc \u062e\u0648\u0627 \u0647\u06d5\u0628\u06ce\u062a \u2014 \u062a\u06c6 \u0628\u06d5\u0647\u06ce\u0632\u062a\u0631\u06cc \u0644\u06d5 \u0648\u06d5\u0633\u0648\u06d5\u0633\u06d5\u06cc \u0634\u06d5\u06cc\u062a\u0627\u0646.","\u0645\u0627\u0646\u062f\u0648\u0648\u0628\u0648\u0648\u0646\u06cc \u062f\u06d5\u0633\u062a\u0646\u0648\u06ce\u0698 \u06a9\u0627\u062a\u06cc\u06cc\u06d5\u060c \u0628\u06d5\u06b5\u0627\u0645 \u067e\u0627\u062f\u0627\u0634\u062a \u0648 \u062d\u06d5\u0633\u0627\u0631\u06d5\u0648\u062a\u06d5\u06a9\u06d5\u06cc \u0647\u06d5\u0645\u06cc\u0634\u06d5\u06cc\u06cc\u06d5.","\u06a9\u0627\u062a\u06ce\u06a9 \u0628\u06d5 \u0626\u0627\u0648\u06cc \u062f\u06d5\u0633\u062a\u0646\u0648\u06ce\u0698 \u0695\u0648\u0648\u062e\u0633\u0627\u0631\u062a \u062f\u06d5\u0634\u06c6\u06cc\u062a\u060c \u0695\u0648\u0648\u0646\u0627\u0643\u06cc\u06cc\u062a \u0628\u06c6 \u0642\u06d5\u0628\u0631 \u062f\u0631\u0648\u0633\u062a \u062f\u06d5\u06a9\u06d5\u06cc\u062a.","\u0628\u06cc\u0631 \u0644\u06d5\u0648 \u0626\u0627\u0631\u0627\u0645\u06cc\u06cc\u06d5 \u0642\u0648\u0648\u06b5\u06d5 \u0628\u06a9\u06d5\u0631\u06d5\u0648\u06d5 \u06a9\u06d5 \u062f\u0648\u0627\u06cc \u0633\u06d5\u0644\u0627\u0645\u062f\u0627\u0646\u06d5\u0648\u06d5\u06cc \u0646\u0648\u06ce\u0698\u06ce\u06a9\u06cc \u062a\u06d5\u0648\u0627\u0648 \u062f\u0627\u062a\u062f\u06d5\u06af\u0631\u06ce\u062a.","\u0647\u06d5\u0631\u06af\u06cc\u0632 \u0628\u06ce\u0647\u06cc\u0648\u0627 \u0645\u06d5\u0628\u06d5 \u0644\u06d5 \u0695\u06d5\u062d\u0645\u06d5\u062a\u06cc \u062e\u0648\u0627 \u0628\u06d5\u0647\u06c6\u06cc \u0632\u06c6\u0631\u06cc \u0646\u0648\u06ce\u0698\u06cc \u0641\u06d5\u0648\u062a\u0627\u0648\u06d5\u06a9\u0627\u0646\u062a\u06d5\u0648\u06d5 \u2014 \u06af\u06d5\u0695\u0627\u0646\u06d5\u0648\u06d5 \u062c\u0648\u0627\u0646\u062a\u0631\u06cc\u0646 \u062a\u06c6\u0628\u06d5\u06cc\u06d5.","\u0628\u0627 \u0646\u0648\u06ce\u0698\u06d5\u06a9\u06d5\u062a \u0628\u06ce\u062a\u06d5 \u0642\u06d5\u06b5\u063a\u0627\u0646\u06cc \u0644\u06d5\u0628\u06d5\u0631\u0627\u0645\u0628\u06d5\u0631 \u0633\u06d5\u062e\u062a\u06cc\u06cc\u06d5\u06a9\u0627\u0646\u06cc \u0698\u06cc\u0627\u0646.","\u0626\u06d5\u06af\u06d5\u0631 \u062f\u06b5\u06cc \u062f\u0627\u06cc\u06a9\u062a \u0648 \u0628\u0627\u0648\u06a9\u062a \u062e\u06c6\u0634 \u062f\u06d5\u06a9\u06d5\u06cc\u062a\u060c \u0646\u0648\u06ce\u0698\u06a9\u0631\u062f\u0646\u062a \u06af\u06d5\u0648\u0631\u06d5\u062a\u0631\u06cc\u0646 \u0634\u0627\u0646\u0627\u0632\u06cc\u06cc\u06d5 \u0628\u06c6 \u0626\u06d5\u0648\u0627\u0646.","\u0626\u06d5\u0648 \u067e\u06ce\u0646\u062c \u062e\u0648\u0644\u06d5\u06a9\u06d5\u06cc \u06a9\u06d5 \u0628\u06c6 \u0646\u0648\u06ce\u0698 \u062a\u06d5\u0631\u062e\u0627\u0646\u06cc \u062f\u06d5\u06a9\u06d5\u06cc\u062a\u060c \u0628\u06d5\u0631\u06d5\u06a9\u06d5\u062a \u0648 \u0647\u06ce\u0632 \u062f\u06d5\u062a\u06d5\u062e\u0634\u06ce\u0646\u06ce\u062a \u0628\u06c6 \u06a9\u0627\u062a\u06d5\u06a9\u0627\u0646\u06cc \u062a\u0631\u06cc\u0634\u062a.","\u0647\u06d5\u0633\u062a\u06d5! \u062f\u06d5\u0631\u06af\u0627\u06cc \u0698\u0648\u0648\u0631\u06d5\u06a9\u06d5\u062a \u062f\u0627\u0628\u062e\u06d5\u060c \u0628\u06d5\u0631\u0645\u0627\u06b5\u06d5\u06a9\u06d5\u062a \u0695\u0627\u0628\u062e\u06d5 \u2014 \u0641\u0631\u0645\u06ce\u0633\u06a9\u06cc \u067e\u06d5\u0634\u06cc\u0645\u0627\u0646\u06cc\u062a \u0644\u06d5\u06af\u06d5\u06b5 \u0633\u0648\u0698\u062f\u06d5\u06a9\u0627\u0646\u062a \u0628\u06ce\u062a.","\u0626\u06d5\u06cc \u0626\u06d5\u0648 \u06a9\u06d5\u0633\u06d5\u06cc \u06a9\u06d5 \u0628\u06d5\u0628\u06ce \u0645\u06d5\u0628\u06d5\u0633\u062a \u0646\u0648\u06ce\u0698\u062a \u0641\u06d5\u0648\u062a\u0627\u0646\u062f\u0648\u0648\u06d5\u060c \u0645\u06d5\u062a\u0631\u0633\u06d5 \u2014 \u067e\u06d5\u0631\u0648\u06d5\u0631\u062f\u06af\u0627\u0631 \u0644\u06ce\u0628\u0648\u0648\u0631\u062f\u06d5\u06cc\u06d5.","\u0647\u06cc\u0686 \u06a9\u0627\u062a\u06ce\u06a9\u060c \u0644\u06d5 \u0647\u06cc\u0686 \u062a\u06d5\u0645\u06d5\u0646\u06ce\u06a9\u062f\u0627\u060c \u062f\u0631\u06d5\u0646\u06af \u0646\u06cc\u06cc\u06d5 \u0628\u06c6 \u0628\u0628\u06cc\u062a\u06d5 \u0646\u0648\u06ce\u0698\u062e\u0648\u06ce\u0646.","\u0644\u06d5\u06af\u06d5\u06b5 \u0647\u06d5\u0631 \u062f\u06d5\u0633\u062a\u0646\u0648\u06ce\u0698\u06ce\u06a9\u062f\u0627\u060c \u0648\u0632\u06d5\u06cc\u06d5\u06a9\u06cc \u0646\u0648\u06ce \u0648 \u067e\u06c6\u0632\u06d5\u062a\u06cc\u06a4 \u0648\u06d5\u0631\u062f\u06d5\u06af\u0631\u06cc\u062a.","\u0628\u0627 \u06af\u06d5\u0648\u0631\u06d5\u062a\u0631\u06cc\u0646 \u0626\u0627\u0645\u0627\u0646\u062c\u062a \u0626\u06d5\u0648\u06d5 \u0628\u06ce\u062a \u06a9\u06d5 \u0646\u0627\u0648\u062a \u0644\u06d5 \u0644\u06cc\u0633\u062a\u06cc \u0646\u0648\u06ce\u0698\u062e\u0648\u06ce\u0646\u0627\u0646\u062f\u0627 \u0644\u0627\u06cc \u0645\u06d5\u0644\u0627\u0626\u06cc\u06a9\u06d5\u062a\u06d5\u06a9\u0627\u0646 \u0628\u0646\u0648\u0648\u0633\u0631\u06ce\u062a.","\u062a\u06c6 \u062a\u06d5\u0646\u0647\u0627 \u0646\u06cc\u062a \u2014 \u0645\u0644\u06cc\u06c6\u0646\u0627\u0646 \u06a9\u06d5\u0633 \u0644\u06d5\u0645 \u0633\u0627\u062a\u06d5\u062f\u0627 \u0695\u0648\u0648\u06cc\u0627\u0646 \u0644\u06d5 \u06cc\u06d5\u06a9 \u0642\u06cc\u0628\u0644\u06d5\u06cc\u06d5. \u067e\u06d5\u06cc\u0648\u06d5\u0646\u062f\u06cc \u0628\u06a9\u06d5 \u0628\u06d5\u0648 \u06a9\u0627\u0631\u0648\u0627\u0646\u06d5 \u067e\u06cc\u0631\u06c6\u0632\u06d5\u0648\u06d5.","\u0634\u06d5\u06cc\u062a\u0627\u0646 \u062f\u06d5\u06cc\u06d5\u0648\u06ce\u062a \u062a\u06d5\u0646\u0647\u0627 \u062e\u06d5\u0645\u0628\u0627\u0631 \u0628\u06cc\u062a \u2014 \u0628\u06cc\u0633\u06d5\u0644\u0645\u06ce\u0646\u06d5 \u06a9\u06d5 \u0647\u06d5\u06b5\u06d5\u06cc\u06d5 \u0648 \u0626\u06ce\u0633\u062a\u0627 \u0642\u06d5\u0632\u0627\u06cc \u0628\u06a9\u06d5\u0631\u06d5\u0648\u06d5.","\u0644\u06d5\u0648\u0627\u0646\u06d5\u06cc\u06d5 \u062f\u06d5\u0633\u062a\u067e\u06ce\u06a9\u0631\u062f\u0646\u06d5\u0648\u06d5 \u0642\u0648\u0631\u0633 \u0628\u06ce\u062a\u060c \u0628\u06d5\u06b5\u0627\u0645 \u0628\u06d5\u0631\u062f\u06d5\u0648\u0627\u0645\u0628\u0648\u0648\u0646 \u0644\u06d5\u0633\u06d5\u0631\u06cc \u067e\u0695 \u0644\u06d5 \u0686\u06ce\u0698\u06cc \u0695\u06c6\u062d\u06cc\u06cc\u06d5\u06a9\u0627\u0646\u06d5.","\u062e\u06c6\u0634\u06d5\u0648\u06cc\u0633\u062a\u06cc \u062e\u0648\u062f\u0627 \u0628\u06c6 \u062a\u06c6 \u0644\u06d5\u0648\u06d5\u062f\u0627\u06cc\u06d5 \u06a9\u06d5 \u062f\u06d5\u0631\u0641\u06d5\u062a\u06cc \u0646\u0648\u06ce\u0698\u06a9\u0631\u062f\u0646 \u0648 \u062a\u06d5\u0646\u062f\u0631\u0648\u0633\u062a\u06cc \u067e\u06ce\u062a \u062f\u0627\u0648\u06d5 \u2014 \u0628\u06d5\u0641\u06cc\u0695\u06c6\u06cc \u0645\u06d5\u062f\u06d5.","\u062a\u06d5\u0645\u0628\u06d5\u06b5\u06cc \u06cc\u0627\u0646 \u0633\u0627\u0631\u062f \u06a9\u06d5\u0634\u0648\u0647\u06d5\u0648\u0627 \u0646\u06d5\u0628\u06ce\u062a\u06d5 \u0695\u06ce\u06af\u0631 \u0644\u06d5 \u06af\u06d5\u0648\u0631\u06d5\u062a\u0631\u06cc\u0646 \u0633\u06d5\u0631\u06a9\u06d5\u0648\u062a\u0646\u062a \u0644\u06d5 \u0695\u06c6\u0698\u06cc \u062f\u0648\u0627\u06cc\u06cc\u062f\u0627.","\u0626\u06d5\u06af\u06d5\u0631 \u062f\u06b5\u062a \u06af\u0631\u0627\u0646 \u062f\u06d5\u0628\u06ce\u062a \u0648 \u0698\u06cc\u0627\u0646 \u0633\u06d5\u062e\u062a \u062f\u06d5\u0628\u06ce\u062a\u060c \u0633\u0648\u0698\u062f\u06d5\u06cc \u062f\u0631\u06ce\u0698 \u0648 \u0647\u0627\u062a\u0648\u0648\u0686\u06c6 \u0628\u06a9\u06d5.","\u0646\u0648\u06ce\u0698 \u062a\u06d5\u0646\u0647\u0627 \u0628\u06d5\u0631\u062f\u06ce\u0648\u0627\u0645\u0628\u0648\u0648\u0646\u06cc \u06a9\u0627\u062a\u06cc \u0646\u06cc\u06cc\u06d5\u060c \u0628\u06d5\u06b5\u06a9\u0648 \u0626\u0627\u0645\u0627\u062f\u06d5\u06a9\u0627\u0631\u06cc\u06cc \u06af\u06c6\u0695\u06d5\u06a9\u06d5 \u0648 \u0628\u06d5\u0647\u06d5\u0634\u062a\u06cc\u0634\u06d5.","\u0695\u06c6\u0698\u06cc \u06a9\u06c6\u062a\u0627\u06cc\u06cc \u06a9\u0627\u062a\u06ce\u06a9 \u0644\u06d5\u0633\u06d5\u0631 \u0628\u06d5\u0631\u062f\u06cc \u0645\u0627\u0646\u06cc\u0634\u0627\u0646\u062a \u0695\u0627\u062f\u06d5\u062f\u06d5\u0646\u060c \u062a\u06d5\u0646\u0647\u0627 \u0646\u0648\u06ce\u0698\u06cc \u067e\u0627\u06a9\u062a \u062f\u06ce\u062a\u06d5 \u06cc\u0627\u0631\u0645\u06d5\u062a\u06cc\u062a."],t.s)
